import {
  getActivityForUser,
  getDraftsForUser,
  getInstalledForUser,
  getPublishedForUser,
  getSavedForUser,
} from "~~/server/utils/queries/profile"
import type {
  ProfileActivityEvent,
  ProfileDraftRow,
  ProfileInstalledRow,
  ProfilePublishedRow,
  ProfileSavedRow,
} from "~~/shared/types"

export type SectionKey = "installed" | "published" | "drafts" | "saved" | "activity"

const KEYS: ReadonlySet<SectionKey> = new Set(["installed", "published", "drafts", "saved", "activity"])

export type SectionResponse =
  | { section: "installed"; rows: ProfileInstalledRow[] }
  | { section: "published"; rows: ProfilePublishedRow[] }
  | { section: "drafts"; rows: ProfileDraftRow[] }
  | { section: "saved"; rows: ProfileSavedRow[] }
  | { section: "activity"; rows: ProfileActivityEvent[] }

// Map Date fields to ISO strings so the endpoint's return type matches what
// crosses the wire. JSON serialization would convert these anyway, but typing
// them as Date and serializing them as string is a footgun that hides
// type/runtime drift.
export default defineEventHandler(async (event): Promise<SectionResponse> => {
  const session = await requireUser(event)
  const raw = getQuery(event).section
  const section = typeof raw === "string" ? raw : "installed"
  if (!KEYS.has(section as SectionKey)) {
    throw createError({ statusCode: 400, statusMessage: "unknown_section" })
  }

  switch (section as SectionKey) {
    case "installed": {
      const rows = await getInstalledForUser(session.id)
      return {
        section: "installed",
        rows: rows.map((r) => ({ ...r, installedAt: r.installedAt.toISOString() })),
      }
    }
    case "published":
      // No Date fields on this row.
      return { section: "published", rows: await getPublishedForUser(session.id) }
    case "drafts": {
      const rows = await getDraftsForUser(session.id)
      return {
        section: "drafts",
        rows: rows.map((r) => ({ ...r, updatedAt: r.updatedAt.toISOString() })),
      }
    }
    case "saved": {
      const rows = await getSavedForUser(session.id)
      return {
        section: "saved",
        rows: rows.map((r) => ({ ...r, savedAt: r.savedAt.toISOString() })),
      }
    }
    case "activity": {
      const rows = await getActivityForUser(session.id)
      return {
        section: "activity",
        rows: rows.map((r) => ({ ...r, at: r.at.toISOString() }) as ProfileActivityEvent),
      }
    }
  }
})

// Pure decision for the install flow's "which version to record" step.
// Same testability story as `shared/extensions/state.ts` — the orchestrator
// loads the candidate list and passes it in; this module just decides.

export interface VersionCandidate {
  version: string
  publishedAt: Date | null
  createdAt: Date
}

export type VersionPick =
  | { ok: true; version: string }
  | { ok: false; error: "no_published_version" }

// `candidates` must already be sorted newest-first
// (`publishedAt DESC NULLS LAST, createdAt DESC` — matches what
// `versionsRepo.listLatestReadyForExtension` returns).
//
// - If the caller passed a specific version, that wins (passthrough).
// - Otherwise pick the first candidate; if there is none, return an error
//   so the orchestrator can map it to its domain exception.
export function pickInstallVersion(input: {
  requested: string | undefined
  candidates: VersionCandidate[]
}): VersionPick {
  const { requested, candidates } = input

  if (requested) return { ok: true, version: requested }

  const latest = candidates[0]
  if (!latest) return { ok: false, error: "no_published_version" }

  return { ok: true, version: latest.version }
}

import { sql } from "drizzle-orm";
import {
  bigint,
  boolean,
  customType,
  index,
  integer,
  jsonb,
  numeric,
  pgEnum,
  pgTable,
  primaryKey,
  text,
  timestamp,
  unique,
} from "drizzle-orm/pg-core";

import { users } from "./auth";
import { departments, organizations } from "./org";

// tsvector is a Postgres-native type; Drizzle doesn't ship a built-in helper.
// We declare it as a custom type so the ORM can reference it in WHERE clauses
// via sql``. It is GENERATED ALWAYS (read-only); never written by app code.
const tsvector = customType<{ data: string }>({
  dataType() { return "tsvector"; },
});

export const extensionCategoryEnum = pgEnum("extension_category", [
  "skills",
  "mcp",
  "slash",
  "plugins",
]);

export const extensionScopeEnum = pgEnum("extension_scope", [
  "personal",
  "org",
  "enterprise",
]);

export const extensionBadgeEnum = pgEnum("extension_badge", [
  "official",
  "popular",
  "new",
]);

export const funcCatEnum = pgEnum("func_cat", [
  "workTask",
  "business",
  "tools",
]);

export const visibilityEnum = pgEnum("extension_visibility", [
  "draft",
  "published",
  "archived",
]);

export const versionStatusEnum = pgEnum("version_status", [
  "pending",
  "scanning",
  "ready",
  "rejected",
]);

export const fileScanStatusEnum = pgEnum("file_scan_status", [
  "pending",
  "clean",
  "flagged",
]);

export const extensions = pgTable(
  "extensions",
  {
    id: text().primaryKey(),
    slug: text().notNull().unique(),
    category: extensionCategoryEnum().notNull(),
    badge: extensionBadgeEnum(),
    scope: extensionScopeEnum().notNull(),
    // funcCat/subCat are nullable — the redesigned publish wizard does not
    // collect them; admin curation can backfill or system defaults apply.
    funcCat: funcCatEnum(),
    subCat: text(),
    l2: text(),
    publisherUserId: text().references(() => users.id, {
      onDelete: "set null",
    }),
    ownerOrgId: text()
      .notNull()
      .references(() => organizations.id, { onDelete: "cascade" }),
    deptId: text().references(() => departments.id, { onDelete: "set null" }),
    iconEmoji: text(),
    iconColor: text(),
    visibility: visibilityEnum().notNull().default("draft"),
    // Editorial flag — hand-curated. Surfaces a single extension on the home
    // hero. Coexists with `badge`: badge is a static editorial mark on the
    // card; `featured` is a transient "pick of the week" pointer.
    featured: boolean().notNull().default(false),
    // i18n columns
    name: text().notNull(),
    nameZh: text(),
    tagline: text(),
    taglineZh: text(),
    description: text(),
    descriptionZh: text(),
    // Long-form markdown body for the detail page. Not duplicated to ZH yet —
    // most extensions will have an English README, with translations layered
    // on later if needed.
    readmeMd: text(),
    // metadata for detail page sidebar
    homepageUrl: text(),
    repoUrl: text(),
    licenseSpdx: text(),
    compatibilityJson: jsonb(),
    // Permissions captured during publish (network/files/runtime/data, etc.).
    // Surfaced on the detail page so users see what the extension wants.
    permissions: jsonb().notNull().default({}),
    // denormalized counters (updated by jobs)
    downloadsCount: integer().notNull().default(0),
    starsAvg: numeric({ precision: 2, scale: 1 }).notNull().default("0.0"),
    ratingsCount: integer().notNull().default(0),
    publishedAt: timestamp({ withTimezone: true }),
    createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
    updatedAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
    searchVector: tsvector("search_vector"),
  },
  (t) => [
    index("idx_ext_category").on(t.category),
    index("idx_ext_scope").on(t.scope),
    index("idx_ext_func_sub_l2").on(t.funcCat, t.subCat, t.l2),
    index("idx_ext_dept_path").using(
      "btree",
      sql`${t.deptId} text_pattern_ops`,
    ),
    index("idx_ext_visibility").on(t.visibility),
    index("idx_ext_downloads").on(sql`${t.downloadsCount} DESC`),
    index("idx_ext_stars").on(sql`${t.starsAvg} DESC`),
    index("idx_ext_featured_published").on(
      t.featured,
      sql`${t.publishedAt} DESC`,
    ),
  ],
);

export const extensionVersions = pgTable(
  "extension_versions",
  {
    id: text().primaryKey(),
    extensionId: text()
      .notNull()
      .references(() => extensions.id, { onDelete: "cascade" }),
    version: text().notNull(), // semver
    changelog: text(),
    changelogZh: text(),
    manifestJson: jsonb(),
    // Logical reference to files.id; no FK constraint to avoid a circular FK
    // with files.extensionVersionId. App code keeps these consistent.
    bundleFileId: text(),
    status: versionStatusEnum().notNull().default("pending"),
    // Source method chosen during publish: zip (only one wired today), git, cli.
    // Stored as text rather than enum so adding methods doesn't require a migration.
    sourceMethod: text().notNull().default("zip"),
    sourceMeta: jsonb().notNull().default({}),
    publishedAt: timestamp({ withTimezone: true }),
    createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
  },
  (t) => [unique("ext_version_unique").on(t.extensionId, t.version)],
);

export const files = pgTable("files", {
  id: text().primaryKey(),
  extensionVersionId: text().references(() => extensionVersions.id, {
    onDelete: "set null",
  }),
  r2Key: text().notNull(),
  size: bigint({ mode: "bigint" }).notNull(),
  checksumSha256: text().notNull(),
  mimeType: text(),
  scanStatus: fileScanStatusEnum().notNull().default("pending"),
  scanReport: jsonb(),
  createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
});

export const tags = pgTable("tags", {
  id: text().primaryKey(), // tag key, e.g. "real-time"
  labelEn: text().notNull(),
  labelZh: text().notNull(),
